import { NextRequest } from "next/server";
import { apiError, apiResponse } from "@/lib/api-auth";
import { getCreditHistory } from "@/lib/actions/payments";
import { authenticateRequestUser } from "@/lib/request-auth";

export async function GET(req: NextRequest) {
  try {
    const user = await authenticateRequestUser(req);
    const transactions = await getCreditHistory(user.id);
    return apiResponse({ transactions });
  } catch (error) {
    return apiError(error);
  }
}
